import type { SearchField, SearchFieldUnit, SearchInstitution, SearchOutputField, Theme } from './types'
import { lookupEnumLabel } from '@/lib/enumLabels'

// Field names rendered first in the sidebar, in order. Unknown fields follow alphabetically by label.
export const PREFERRED_ORDER = ['name', 'city', 'state']

export function sortFields(fields: SearchField[]): SearchField[] {
  return [...fields].sort((a, b) => {
    const ai = PREFERRED_ORDER.indexOf(a.name)
    const bi = PREFERRED_ORDER.indexOf(b.name)
    if (ai !== -1 && bi !== -1) return ai - bi
    if (ai !== -1) return -1
    if (bi !== -1) return 1
    return a.label.localeCompare(b.label)
  })
}

// Ordered list of themes for sidebar rendering. Only themes with fields are shown.
export const THEME_ORDER: Theme[] = [
  'CORE',
  'LOCATION',
  'ACADEMICS',
  'COST',
  'OUTCOMES',
  'RANKING',
  'ADMISSIONS',
  'ATHLETICS',
  'FIELDS_OF_STUDY',
  'CULTURAL_ENVIRONMENT',
  'WEATHER',
]

export const THEME_LABELS: Record<Theme, string> = {
  CORE: 'Core',
  LOCATION: 'Location',
  ACADEMICS: 'Academics',
  COST: 'Cost & Financial Aid',
  OUTCOMES: 'Outcomes',
  RANKING: 'Rankings',
  ADMISSIONS: 'Admissions',
  ATHLETICS: 'Athletics',
  FIELDS_OF_STUDY: 'Fields of Study',
  CULTURAL_ENVIRONMENT: 'Cultural Environment',
  WEATHER: 'Weather & Climate',
  PHYSICAL_ENVIRONMENT: 'Physical Environment',
  DEMOGRAPHICS: 'Demographics',
  REPUTATION: 'Reputation',
  SAFETY: 'Safety',
  STUDENT_LIFE: 'Student Life',
  METADATA: 'Metadata',
  OTHER: 'Other',
}

export interface ThemeGroup {
  theme: Theme
  label: string
  fields: SearchField[]
}

export function fieldsByTheme(fields: SearchField[]): ThemeGroup[] {
  // Group fields by theme
  const grouped = new Map<Theme, SearchField[]>()
  for (const f of fields) {
    const existing = grouped.get(f.theme)
    if (existing) {
      existing.push(f)
    } else {
      grouped.set(f.theme, [f])
    }
  }

  // Sort fields within each group alphabetically by label
  for (const group of grouped.values()) {
    group.sort((a, b) => a.label.localeCompare(b.label))
  }

  // Build ordered result: known themes first, then any unknown themes
  const result: ThemeGroup[] = []
  for (const theme of THEME_ORDER) {
    const group = grouped.get(theme)
    if (group && group.length > 0) {
      result.push({ theme, label: THEME_LABELS[theme], fields: group })
      grouped.delete(theme)
    }
  }
  // Append any remaining themes not in THEME_ORDER
  for (const [theme, group] of grouped) {
    if (group.length > 0) {
      result.push({ theme, label: THEME_LABELS[theme] ?? String(theme), fields: group })
    }
  }

  return result
}

const MILES_TO_KM = 1.60934

export function buildFilterInputs(
  filters: Record<string, unknown>,
): Array<{ field: string; value: unknown }> {
  return Object.entries(filters).map(([field, value]) => {
    if (
      typeof value === 'object' &&
      value !== null &&
      'latitude' in value &&
      'longitude' in value &&
      'radiusMiles' in value
    ) {
      const v = value as { latitude: number; longitude: number; radiusMiles: number }
      return {
        field,
        value: {
          kind: 'radius',
          radius: { lat: v.latitude, lng: v.longitude, radius_km: v.radiusMiles * MILES_TO_KM },
        },
      }
    }
    return { field, value }
  })
}

export function serializeFilterValue(value: unknown): string {
  if (typeof value === 'object' && value !== null) {
    if ('query' in value) return String((value as { query: string }).query)
    if ('value' in value) return String((value as { value: string }).value)
    if ('values' in value) return (value as { values: string[] }).values.join(',')
    if ('latitude' in value && 'longitude' in value && 'radiusMiles' in value) {
      const g = value as { latitude: number; longitude: number; radiusMiles: number }
      return `${g.latitude},${g.longitude},${g.radiusMiles}`
    }
    if ('max' in value && !('min' in value))
      return String((value as { max: number }).max)
    if ('min' in value && !('max' in value))
      return String((value as { min: number }).min)
    if ('min' in value && 'max' in value) {
      const r = value as { min: number; max: number }
      return `${r.min},${r.max}`
    }
  }
  return String(value)
}

export function parseUrlToFilters(
  params: URLSearchParams,
  fields: SearchField[],
): Record<string, unknown> {
  const filters: Record<string, unknown> = {}
  const fieldMap = new Map(fields.map((f) => [f.name, f]))

  // Handle legacy ?q= param — maps to the "name" field
  const q = params.get('q')
  if (q && !params.has('name')) {
    filters.name = { query: q }
  }

  for (const [key, raw] of params.entries()) {
    if (key === 'q') continue
    const field = fieldMap.get(key)
    if (!field) continue

    if (field.__typename === 'TextSearchField') {
      filters[key] = { query: raw }
    } else if (field.__typename === 'BinarySearchField') {
      filters[key] = { value: raw }
    } else if (field.__typename === 'ChoiceSearchField') {
      if (field.maxSelections === 1) {
        filters[key] = { value: raw }
      } else {
        filters[key] = { values: raw.split(',').filter(Boolean) }
      }
    } else if (field.__typename === 'NumericalSearchField') {
      const num = Number(raw)
      if (!isNaN(num)) {
        filters[key] = { value: num }
      }
    } else if (field.__typename === 'GeoSearchField') {
      const parts = raw.split(',')
      if (parts.length === 3) {
        const [lat, lng, r] = parts.map(Number)
        if (!isNaN(lat) && !isNaN(lng) && !isNaN(r)) {
          filters[key] = { latitude: lat, longitude: lng, radiusMiles: r }
        }
      }
    } else if (field.__typename === 'NumericalRangeSearchField') {
      if (raw.includes(',')) {
        const [minStr, maxStr] = raw.split(',')
        const minVal = Number(minStr)
        const maxVal = Number(maxStr)
        if (!isNaN(minVal) && !isNaN(maxVal)) {
          filters[key] = { min: minVal, max: maxVal }
        }
      } else {
        const num = Number(raw)
        if (!isNaN(num)) {
          filters[key] = { max: num }
        }
      }
    }
  }

  return filters
}

export interface OutputFieldThemeGroup {
  theme: Theme
  label: string
  fields: SearchOutputField[]
}

export function outputFieldsByTheme(fields: SearchOutputField[]): OutputFieldThemeGroup[] {
  const grouped = new Map<Theme, SearchOutputField[]>()
  for (const f of fields) {
    const existing = grouped.get(f.theme)
    if (existing) {
      existing.push(f)
    } else {
      grouped.set(f.theme, [f])
    }
  }

  const result: OutputFieldThemeGroup[] = []
  for (const theme of THEME_ORDER) {
    const group = grouped.get(theme)
    if (group && group.length > 0) {
      result.push({ theme, label: THEME_LABELS[theme], fields: group })
      grouped.delete(theme)
    }
  }
  for (const [theme, group] of grouped) {
    if (group.length > 0) {
      result.push({ theme, label: THEME_LABELS[theme] ?? String(theme), fields: group })
    }
  }

  return result
}

/**
 * Navigates a dot-path (e.g. "academics.enrollment") into a SearchInstitution
 * and returns the leaf value. Returns undefined if any segment is missing.
 */
export function getFieldValue(
  inst: SearchInstitution,
  outputKey: string | null | undefined,
): unknown {
  if (!outputKey) return undefined
  const parts = outputKey.split('.')
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  let current: any = inst
  for (const part of parts) {
    if (current == null || typeof current !== 'object') return undefined
    current = current[part]
  }
  return current ?? undefined
}

/**
 * Parse a blend URL param like "rank_us_news_national:40,rank_forbes:30" into a record.
 */
export function parseBlendParam(raw: string | null): Record<string, number> {
  if (!raw) return {}
  const result: Record<string, number> = {}
  for (const pair of raw.split(',')) {
    const [field, weightStr] = pair.split(':')
    if (field && weightStr) {
      const weight = Number(weightStr)
      if (!isNaN(weight) && weight > 0) {
        result[field] = weight
      }
    }
  }
  return result
}

/**
 * Serialize blend weights to a URL param string.
 * Only includes non-zero weights.
 */
export function serializeBlendWeights(weights: Record<string, number>): string {
  return Object.entries(weights)
    .filter(([, w]) => w > 0)
    .map(([field, weight]) => `${field}:${weight}`)
    .join(',')
}

export function formatCellValue(
  value: unknown,
  unit?: SearchFieldUnit | null,
  fieldName?: string,
): string {
  if (value === null || value === undefined || value === '') return '—'
  if (fieldName) {
    const label = lookupEnumLabel(fieldName, String(value))
    if (label !== null) return label
  }
  const num = Number(value)
  if (unit === 'DOLLARS' && !isNaN(num)) {
    return `$${Math.round(num).toLocaleString()}`
  }
  if (unit === 'PERCENTAGE' && !isNaN(num)) {
    return `${(num * 100).toFixed(1)}%`
  }
  if (unit === 'MILES' && !isNaN(num)) {
    return `${num.toLocaleString()} mi`
  }
  return String(value)
}

