/**
 * Predefined step values for enrollment and cost range dropdowns.
 *
 * Instead of free-text number inputs, these fields render as <Select>
 * dropdowns with human-friendly breakpoints.
 */

// ---------------------------------------------------------------------------
// Enrollment steps
// 0, 1000, 2000, ... 10,000 (by 1,000)
// then 12,500, 15,000, ... 50,000 (by 2,500)
// ---------------------------------------------------------------------------

const ENROLLMENT_STEP_LOW = 1_000
const ENROLLMENT_STEP_LOW_MAX = 10_000
const ENROLLMENT_STEP_HIGH = 2_500
const ENROLLMENT_STEP_HIGH_MAX = 50_000

export function generateEnrollmentSteps(): number[] {
  const steps: number[] = [0]
  for (let v = ENROLLMENT_STEP_LOW; v <= ENROLLMENT_STEP_LOW_MAX; v += ENROLLMENT_STEP_LOW) {
    steps.push(v)
  }
  for (
    let v = ENROLLMENT_STEP_LOW_MAX + ENROLLMENT_STEP_HIGH;
    v <= ENROLLMENT_STEP_HIGH_MAX;
    v += ENROLLMENT_STEP_HIGH
  ) {
    steps.push(v)
  }
  return steps
}

// ---------------------------------------------------------------------------
// Cost steps (USD)
// 0, 5000, 10,000, ... 30,000 (by $5,000)
// then 40,000, 50,000, ... 80,000 (by $10,000)
// ---------------------------------------------------------------------------

const COST_STEP_LOW = 5_000
const COST_STEP_LOW_MAX = 30_000
const COST_STEP_HIGH = 10_000
const COST_STEP_HIGH_MAX = 80_000

export function generateCostSteps(): number[] {
  const steps: number[] = [0]
  for (let v = COST_STEP_LOW; v <= COST_STEP_LOW_MAX; v += COST_STEP_LOW) {
    steps.push(v)
  }
  for (
    let v = COST_STEP_LOW_MAX + COST_STEP_HIGH;
    v <= COST_STEP_HIGH_MAX;
    v += COST_STEP_HIGH
  ) {
    steps.push(v)
  }
  return steps
}

// ---------------------------------------------------------------------------
// Formatting
// ---------------------------------------------------------------------------

function formatNumber(n: number): string {
  return n.toLocaleString('en-US')
}

export function formatEnrollmentLabel(value: number): string {
  return formatNumber(value)
}

export function formatCostLabel(value: number): string {
  return `$${formatNumber(value)}`
}

// ---------------------------------------------------------------------------
// Select option builders
// ---------------------------------------------------------------------------

export interface StepSelectOption {
  value: string
  label: string
}

const UNLIMITED_VALUE = ''
const UNLIMITED_LABEL = 'No limit'

type StepKind = 'enrollment' | 'cost'

function buildOptions(kind: StepKind): StepSelectOption[] {
  const steps = kind === 'enrollment' ? generateEnrollmentSteps() : generateCostSteps()
  const fmt = kind === 'enrollment' ? formatEnrollmentLabel : formatCostLabel
  const options: StepSelectOption[] = steps.map((v) => ({
    value: String(v),
    label: fmt(v),
  }))
  options.push({ value: UNLIMITED_VALUE, label: UNLIMITED_LABEL })
  return options
}

// Field names that use dropdown steps
const ENROLLMENT_FIELDS = new Set(['enrollment', 'grad_enrollment'])
const COST_FIELDS = new Set([
  'tuition_in_state',
  'tuition_out_of_state',
  'avg_net_price',
  'avg_net_price_0_30k',
  'endowment',
])

// Cached option lists (generated once)
let enrollmentOptions: StepSelectOption[] | null = null
let costOptions: StepSelectOption[] | null = null

/**
 * Returns dropdown options for a field if it should use a step-based select,
 * or null if the field should keep its text input.
 */
export function getStepOptions(fieldName: string): StepSelectOption[] | null {
  if (ENROLLMENT_FIELDS.has(fieldName)) {
    if (!enrollmentOptions) enrollmentOptions = buildOptions('enrollment')
    return enrollmentOptions
  }
  if (COST_FIELDS.has(fieldName)) {
    if (!costOptions) costOptions = buildOptions('cost')
    return costOptions
  }
  return null
}

/**
 * Convert a numeric filter value to the Select's string value.
 * undefined/null → '' (the "No limit" option).
 */
export function valueToSelectString(v: number | undefined): string {
  return v !== undefined ? String(v) : UNLIMITED_VALUE
}

/**
 * Convert a Select string value back to a number or undefined.
 * '' (No limit) → undefined.
 */
export function selectStringToValue(s: string | null): number | undefined {
  if (s === null || s === UNLIMITED_VALUE) return undefined
  const n = Number(s)
  return isNaN(n) ? undefined : n
}

