import { describe, it, expect } from 'vitest'
import {
  generateEnrollmentSteps,
  generateCostSteps,
  formatEnrollmentLabel,
  formatCostLabel,
  getStepOptions,
  valueToSelectString,
  selectStringToValue,
} from './rangeSteps'

describe('generateEnrollmentSteps', () => {
  it('starts at 0', () => {
    const steps = generateEnrollmentSteps()
    expect(steps[0]).toBe(0)
  })

  it('increments by 1,000 up to 10,000', () => {
    const steps = generateEnrollmentSteps()
    // 0, 1000, 2000, ... 10000 = 11 values
    for (let i = 0; i <= 10; i++) {
      expect(steps[i]).toBe(i * 1000)
    }
  })

  it('increments by 2,500 from 12,500 to 50,000', () => {
    const steps = generateEnrollmentSteps()
    // After index 10 (10000), next values: 12500, 15000, ... 50000
    expect(steps[11]).toBe(12_500)
    expect(steps[12]).toBe(15_000)
    expect(steps[steps.length - 1]).toBe(50_000)
  })

  it('has expected total count', () => {
    const steps = generateEnrollmentSteps()
    // 0..10000 by 1000 = 11 values, 12500..50000 by 2500 = 16 values → 27 total
    expect(steps).toHaveLength(27)
  })
})

describe('generateCostSteps', () => {
  it('starts at 0', () => {
    const steps = generateCostSteps()
    expect(steps[0]).toBe(0)
  })

  it('increments by 5,000 up to 30,000', () => {
    const steps = generateCostSteps()
    // 0, 5000, 10000, ... 30000 = 7 values
    for (let i = 0; i <= 6; i++) {
      expect(steps[i]).toBe(i * 5000)
    }
  })

  it('increments by 10,000 from 40,000 to 80,000', () => {
    const steps = generateCostSteps()
    expect(steps[7]).toBe(40_000)
    expect(steps[8]).toBe(50_000)
    expect(steps[steps.length - 1]).toBe(80_000)
  })

  it('has expected total count', () => {
    const steps = generateCostSteps()
    // 0..30000 by 5000 = 7 values, 40000..80000 by 10000 = 5 values → 12 total
    expect(steps).toHaveLength(12)
  })
})

describe('formatEnrollmentLabel', () => {
  it('formats with commas', () => {
    expect(formatEnrollmentLabel(0)).toBe('0')
    expect(formatEnrollmentLabel(1_000)).toBe('1,000')
    expect(formatEnrollmentLabel(12_500)).toBe('12,500')
    expect(formatEnrollmentLabel(50_000)).toBe('50,000')
  })
})

describe('formatCostLabel', () => {
  it('formats with $ prefix and commas', () => {
    expect(formatCostLabel(0)).toBe('$0')
    expect(formatCostLabel(5_000)).toBe('$5,000')
    expect(formatCostLabel(30_000)).toBe('$30,000')
    expect(formatCostLabel(80_000)).toBe('$80,000')
  })
})

describe('getStepOptions', () => {
  it('returns enrollment options for enrollment fields', () => {
    const opts = getStepOptions('enrollment')
    expect(opts).not.toBeNull()
    expect(opts![0]).toEqual({ value: '0', label: '0' })
    expect(opts![1]).toEqual({ value: '1000', label: '1,000' })
    // Last option is "No limit"
    expect(opts![opts!.length - 1]).toEqual({ value: '', label: 'No limit' })
  })

  it('returns enrollment options for grad_enrollment', () => {
    expect(getStepOptions('grad_enrollment')).not.toBeNull()
  })

  it('returns cost options for tuition fields', () => {
    const opts = getStepOptions('tuition_in_state')
    expect(opts).not.toBeNull()
    expect(opts![0]).toEqual({ value: '0', label: '$0' })
    expect(opts![1]).toEqual({ value: '5000', label: '$5,000' })
    expect(opts![opts!.length - 1]).toEqual({ value: '', label: 'No limit' })
  })

  it('returns cost options for other cost fields', () => {
    expect(getStepOptions('tuition_out_of_state')).not.toBeNull()
    expect(getStepOptions('avg_net_price')).not.toBeNull()
    expect(getStepOptions('avg_net_price_0_30k')).not.toBeNull()
    expect(getStepOptions('endowment')).not.toBeNull()
  })

  it('returns null for non-dropdown fields', () => {
    expect(getStepOptions('pell_grant_rate')).toBeNull()
    expect(getStepOptions('admission_rate')).toBeNull()
    expect(getStepOptions('name')).toBeNull()
  })
})

describe('valueToSelectString', () => {
  it('converts number to string', () => {
    expect(valueToSelectString(5000)).toBe('5000')
    expect(valueToSelectString(0)).toBe('0')
  })

  it('converts undefined to empty string', () => {
    expect(valueToSelectString(undefined)).toBe('')
  })
})

describe('selectStringToValue', () => {
  it('converts string to number', () => {
    expect(selectStringToValue('5000')).toBe(5000)
    expect(selectStringToValue('0')).toBe(0)
  })

  it('converts empty string to undefined', () => {
    expect(selectStringToValue('')).toBeUndefined()
  })

  it('converts null to undefined', () => {
    expect(selectStringToValue(null)).toBeUndefined()
  })
})

